// ── CSV parser ───────────────────────────────────────────────────────────────
function parseCSV(raw) {
  if (!raw || !raw.trim()) return [];
  const lines = raw.trim().split('\n').map(l => l.replace(/\r$/, ''));
  if (lines.length < 2) return [];

  const header = [];
  let cur = '', inQ = false;
  for (const ch of lines[0] + ',') {
    if (ch === '"') { inQ = !inQ; }
    else if (ch === ',' && !inQ) { header.push(cur.trim()); cur = ''; }
    else cur += ch;
  }

  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    if (!lines[i].trim()) continue;
    const values = [];
    cur = ''; inQ = false;
    for (const ch of lines[i] + ',') {
      if (ch === '"') { inQ = !inQ; }
      else if (ch === ',' && !inQ) { values.push(cur.trim()); cur = ''; }
      else cur += ch;
    }
    const obj = {};
    header.forEach((h, idx) => { obj[h] = values[idx] ?? ''; });
    rows.push(obj);
  }
  return rows;
}

// ── Inputs ────────────────────────────────────────────────────────────────────
const bottlesRaw = $input.all()[0].json.data;
const notesRaw   = $input.all()[1].json.data;

const bottles = parseCSV(bottlesRaw);
const notes   = parseCSV(notesRaw);

// ── Index notes by iWine ──────────────────────────────────────────────────────
const notesByWine = {};
for (const n of notes) {
  const id = n.iWine || n.iwine;
  if (!id) continue;
  if (!notesByWine[id]) notesByWine[id] = { texts: [], latestDate: null };
  if (n.Note && n.Note.trim()) notesByWine[id].texts.push(n.Note.trim());
  if (n.Date) {
    const d = new Date(n.Date);
    if (!notesByWine[id].latestDate || d > new Date(notesByWine[id].latestDate))
      notesByWine[id].latestDate = n.Date;
  }
}

// ── Coercions ─────────────────────────────────────────────────────────────────
const toInt   = v => (v !== '' && v != null && !isNaN(parseInt(v,10)))  ? parseInt(v,10)   : null;
const toFloat = v => (v !== '' && v != null && !isNaN(parseFloat(v)))   ? parseFloat(v)    : null;
const toStr   = v => (v !== '' && v != null) ? String(v).trim() : null;

// ── Build output ──────────────────────────────────────────────────────────────
const output = [];
for (const row of bottles) {
  const ibottle = row.iBottle || row.ibottle;
  const iwine   = row.iWine   || row.iwine;
  if (!ibottle) continue;

  const noteData  = notesByWine[iwine] || { texts: [], latestDate: null };
  const my_notes  = noteData.texts.length > 0 ? noteData.texts.join(' | ') : null;
  const note_date = noteData.latestDate || null;

  // Rich text blob for embedding — more context = better semantic recall
  const parts = [
    toStr(row.Wine),
    toInt(row.Vintage) && row.Vintage !== '0' ? `Vintage ${row.Vintage}` : null,
    toStr(row.Producer),
    toStr(row.Type),
    toStr(row.Color),
    toStr(row.Category),
    toStr(row.Locale),
    toStr(row.Appellation),
    toStr(row.Region),
    toStr(row.Country),
    toStr(row.Location) ? `Location: ${row.Location}` : null,
    toStr(row.Bin)      ? `Bin: ${row.Bin}` : null,
    toInt(row.BeginConsume) && toInt(row.EndConsume)
      ? `Drink ${row.BeginConsume}–${row.EndConsume}` : null,
    toFloat(row.CT)      ? `CellarTracker score ${row.CT}` : null,
    toFloat(row.MyScore) ? `My score ${row.MyScore}` : null,
    toFloat(row.PurchasePrice) ? `Purchased at $${row.PurchasePrice}` : null,
    my_notes ? `Tasting notes: ${my_notes}` : null
  ].filter(Boolean);

  output.push({
    json: {
      ct_ibottle:     toInt(ibottle),
      ct_iwine:       toInt(iwine),
      wine:           toStr(row.Wine),
      vintage:        toInt(row.Vintage),
      producer:       toStr(row.Producer),
      wine_type:      toStr(row.Type),
      color:          toStr(row.Color),
      varietal:       toStr(row.Category),
      appellation:    toStr(row.Appellation),
      region:         toStr(row.Region),
      country:        toStr(row.Country),
      locale:         toStr(row.Locale),
      location:       toStr(row.Location),
      bin:            toStr(row.Bin),
      purchase_price: toFloat(row.PurchasePrice),
      valuation:      toFloat(row.Valuation),
      drink_from:     toInt(row.BeginConsume),
      drink_to:       toInt(row.EndConsume),
      ct_score:       toFloat(row.CT),
      my_score:       toFloat(row.MyScore),
      my_notes,
      note_date,
      removed_at:     null,
      last_synced_at: new Date().toISOString(),
      raw_ct_row:     JSON.stringify(row),
      embedding_text: parts.join('. ')
    }
  });
}

return output;

// The embedding HTTP call replaced $json with the OpenRouter response.
// Recover the original wine record from the Parse node via item pairing.
const oai    = $json;
const wine   = $('Parse CSV + Merge Notes').item.json;

const embedding = oai?.data?.[0]?.embedding;
if (!embedding || !Array.isArray(embedding)) {
  throw new Error(`No embedding returned for wine: ${wine.wine} (iBottle ${wine.ct_ibottle})`);
}

return {
  json: {
    ...wine,
    embedding:      `[${embedding.join(',')}]`,   // Supabase REST expects stringified vector
    embedding_text: undefined                      // don't persist the raw text blob
  }
};

// After all batches complete, collect every ct_ibottle that was in today's CT export.
// The soft-delete PATCH will mark any row NOT in this list.
const all = $input.all();
const activeBottles = [...new Set(
  all.map(i => i.json.ct_ibottle).filter(Boolean)
)];
return [{ json: { active_bottles: activeBottles, count: activeBottles.length } }];

const upsertCount   = $('Collect Active iBottle IDs').first().json.count;
const today         = new Date().toISOString().slice(0,10);
const summary       = `Wine inventory sync ${today}: ${upsertCount} bottles upserted/refreshed from CellarTracker. Soft-delete sweep complete.`;
return [{ json: { summary } }];
